+import { $internal } from '../common';
+import { isRelation, isRelationPair } from '../relation/utils/is-relation';
+import { getTrait, hasTrait } from '../trait/trait';
+import type { IsTag, Trait, TraitRecord } from '../trait/types';
+import type { Entity } from '../entity/types';
+import type { World } from '../world';
+
+export const $predicate = Symbol('predicate');
+
+export type PredicateDependencies<T extends Trait[]> = {
+    [K in keyof T]: T[K] extends Trait ? TraitRecord<T[K]> : never;
+};
+
+export type Predicate<T extends Trait[] = Trait[]> = {
+    readonly [$predicate]: true;
+    readonly id: number;
+    readonly dependencies: T;
+    readonly test: (data: PredicateDependencies<T>) => boolean;
+};
+
+let predicateId = 0;
+
+export function createPredicate<T extends Trait[]>(
+    dependencies: T & { [K in keyof T]: IsTag<T[K]> extends true ? never : T[K] },
+    test: (data: PredicateDependencies<T>) => boolean
+): Predicate<T> {
+    for (const dependency of dependencies) {
+        if (
+            isRelation(dependency as any) ||
+            isRelationPair(dependency as any) ||
+            dependency[$internal].type === 'tag'
+        ) {
+            throw new Error('Koota: Predicate dependencies must be data traits, not tags or relations.');
+        }
+    }
+
+    return Object.freeze({ [$predicate]: true as const, id: predicateId++, dependencies, test });
+}
+
+export function isPredicate(value: unknown): value is Predicate {
+    return !!(value as Predicate | undefined)?.[$predicate];
+}
+
+export function matchesPredicate(world: World, entity: Entity, predicate: Predicate): boolean {
+    const values: TraitRecord<Trait>[] = [];
+    for (const dependency of predicate.dependencies) {
+        if (!hasTrait(world, entity, dependency)) return false;
+        values.push(getTrait(world, entity, dependency)!);
+    }
+    return predicate.test(values);
+}
