/* @inline */ function setTraitForTrait(
    world: World,
    entity: Entity,
    trait: Trait,
    value: any,
    triggerChanged: boolean
) {
    const ctx = trait[$internal];
    const store = getStore(world, trait);
    const index = getEntityId(entity);

